dict.string:
$(SUPABASE_URL)
//  ContentView.swift
//  miniRecipe
//
//  Created by Shivani Verma on 11/12/25.
//

import SwiftUI
import Supabase

struct ContentView: View {
    @State private var statusMessage: String = "Ready"

    var body: some View {
        VStack(spacing: 20) {
            Image(systemName: "globe")
                .imageScale(.large)
                .foregroundStyle(.tint)
                .font(.system(size: 48))
            Text("miniRecipe")
                .font(.title2)
                .bold()

            Text(statusMessage)
                .font(.subheadline)
                .foregroundColor(.secondary)
                .multilineTextAlignment(.center)
                .padding(.horizontal)

            HStack(spacing: 16) {
                Button("Print Config") {
                    printConfig()
                }
                .buttonStyle(.borderedProminent)

                Button("Test Supabase") {
                    Task {
                        await testSupabase()
                    }
                }
                .buttonStyle(.bordered)
            }
        }
        .padding()
        .onAppear {
            // quick auto-check on appear
            printConfig()
            Task { await testSupabase() }
        }
    }

    private func printConfig() {
        print("=== Config values ===")
        print("SUPABASE_URL:", Config.supabaseURL.absoluteString)
        let anon = Config.supabaseAnonKey
        print("SUPABASE_ANON_KEY (prefix):", String(anon.prefix(12)) + "...")
        print("=====================")
        statusMessage = "Config printed to console"
    }

    private func testSupabase() async {
        await MainActor.run { statusMessage = "Testing Supabase..." }

        struct RecipeRow: Decodable {
            let id: Int?
            let title: String?
        }

        do {
            let rows: [RecipeRow] = try await SupabaseManager.shared.client
                .from("recipes")
                .select()
                .limit(3)
                .execute()
                .value

            print("Received rows count:", rows.count)

            if !rows.isEmpty {
                print("Received rows:", rows)
                await MainActor.run { statusMessage = "Supabase OK — got \(rows.count) recipe(s)" }
            } else {
                await MainActor.run { statusMessage = "Supabase OK — no recipes returned" }
            }
        } catch {
            print("Supabase DB test failed:", error)
            await MainActor.run { statusMessage = "Supabase test failed: \(error.localizedDescription)" }
        }
    }
}

struct ContentView_Previews: PreviewProvider {
    static var previews: some View {
        ContentView()
    }
}
